+        assert_eq!(help.width, 80);
+        assert!(help.show_all);
+    }
+
+    #[test]
+    fn test_should_render_column() {
+        let enabled = Binding::new().keys(&["q"]).help("q", "quit");
+        let disabled = Binding::new().keys(&["x"]).help("x", "exit").set_enabled(false);
