+    pub cursor: Cursor,
+    /// Character limit (0 = no limit).
+    pub char_limit: usize,
+    /// Maximum height in rows.
+    pub max_height: usize,
+    /// Maximum width in columns.
+    pub max_width: usize,
+    /// Current style (points to focused or blurred).
+    use_focused_style: bool,
